// Emotion 默认向 head 写 data-emotion=react-diff 样式;只把本次新增 style 搬入 shadow(铁律 2)
import React from 'https://cdn.jsdelivr.net/npm/react@19/+esm'; import { createRoot } from 'https://cdn.jsdelivr.net/npm/react-dom@19/client/+esm'; import DiffViewer,{DiffMethod} from 'https://cdn.jsdelivr.net/npm/react-diff-viewer-continued@4/+esm';
const observer = new MutationObserver(records => { for (const r of records) for (const n of r.addedNodes) if (n.nodeType === 1 && n.matches('style[data-emotion^="react-diff"]')) shadowRoot.appendChild(n); }); observer.observe(document.head,{childList:true});
const holder = shadowRoot.appendChild(document.createElement('div')); holder.style.cssText = 'max-height:400px;overflow:auto';
createRoot(holder).render(React.createElement(DiffViewer,{oldValue:data.oldValue,newValue:data.newValue,splitView:data.splitView ?? true,compareMethod:DiffMethod[data.compareMethod ?? 'CHARS'],showDiffOnly:data.showDiffOnly ?? true,useDarkTheme:data.useDarkTheme ?? false,disableWorker:!(data.useWorker ?? false)}));
